import os
import pymysql
from google.cloud import secretsmanager
from google.oauth2 import service_account
from googleapiclient.http import MediaFileUpload

def request(request):
    # Load Cloud SQL connection details from Secret Manager
    client = secretsmanager.SecretsManagerServiceClient()
    response = client.create_secret_version(
        name="projects/<your-project-id>/secrets/cloudsql/versions/latest",
        revisions=[],
        secret=bytes(os.getenv("SQL_CONNECTION_STRING"), "utf-8")
    )
    connection = pymysql.connect(**response.secret_version.data['database'])

    # Query parameters from request
    query = request.GET.get('query', '')

    # Build dynamic SQL query
    cursor = connection.cursor()
    cursor.execute(f"SELECT * FROM your_table WHERE {query}")
    results = cursor.fetchall()

    # Return results as JSON
    response = {'results': list(results)}
    return response